// TC-002: Documents Page (fixture-backed)
// Fixture seeds docs/sample.md so the Documents query returns at least one
// document. The new project-scoped Documents UI is a table (Title/Path)
// where row-click navigates to a markdown detail view with an Edit button.
// ---------------------------------------------------------------------------
test.describe('TC-002: Documents', () => {
  let ids: { nodeId: string; projectId: string; nodeName: string }

  test.beforeEach(async ({ page, request }) => {
    ids = await getFixtureIds(request)
    await page.goto(`${projectBase(ids)}/documents`)
    await page.waitForSelector('h1')
  })

  test('TC-002.1 — document list loads from fixture', async ({ page }) => {
    await expect(page.locator('h1')).toContainText('Documents')
    // Fixture seeds at least one doc; total-count badge reflects that.
    await expect(page.getByText(/\d+ total/)).toBeVisible()
    const rows = page.locator('tbody tr')
    expect(await rows.count()).toBeGreaterThan(0)
  })

  test('TC-002.2 — fixture document title and path render', async ({ page }) => {
    const firstRow = page.locator('tbody tr').first()
    await expect(firstRow).toBeVisible()
    // Path column uses font-mono and shows the fixture-relative path.
    const pathCell = firstRow.locator('td.font-mono')
    await expect(pathCell).toBeVisible()
    await expect(pathCell).toContainText(/\.md$/)
  })

  test('TC-002.3 — selecting a row opens the document detail', async ({ page }) => {
    const firstRow = page.locator('tbody tr').first()
    await firstRow.click()
    await expect(page).toHaveURL(new RegExp(`${projectBase(ids)}/documents/.+`))
    // Detail page exposes an Edit affordance for fixture markdown docs.
    await expect(page.getByRole('button', { name: /^Edit$/ })).toBeVisible({ timeout: 5000 })
  })

  test('TC-002.4 — document detail renders sanitized markdown body', async ({ page }) => {
    await page.locator('tbody tr').first().click()
    await expect(page.locator('h1')).toBeVisible({ timeout: 5000 })
    // The fixture sample.md begins with "# Sample fixture document".
    await expect(page.getByRole('heading', { name: /Sample fixture document/i })).toBeVisible()
  })
})

